previewCss:
.darma-loader-darma-research-cosmic-eclipse-core { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #f59e0b); --accent-2: var(--loader-secondary-color, #ef4444); width: var(--loader-size, 92px); height: var(--loader-size, 92px); border-radius: 50%; position: relative; background: radial-gradient(circle at 45% 45%, var(--accent) 0 28%, color-mix(in srgb, var(--accent-2) 75%, #000) 56%, #020617 70%); box-shadow: 0 0 calc(var(--loader-size, 92px) * .45) color-mix(in srgb, var(--accent) 55%, transparent); overflow: hidden; animation: darma-loader-darma-research-cosmic-eclipse-core-eclipse-pulse calc(var(--speed) * 2) ease-in-out infinite; }
.darma-loader-darma-research-cosmic-eclipse-core::before { content: ""; position: absolute; inset: -30%; border-radius: 50%; background: repeating-conic-gradient(from 0deg, #fff3 0 5deg, transparent 5deg 18deg); animation: darma-loader-darma-research-cosmic-eclipse-core-eclipse-rays calc(var(--speed) * 5) linear infinite; }
.darma-loader-darma-research-cosmic-eclipse-core__moon { position: absolute; width: 70%; height: 70%; border-radius: 50%; background: #020617; top: 12%; left: -12%; box-shadow: inset -10px 0 18px #ffffff12; animation: darma-loader-darma-research-cosmic-eclipse-core-eclipse-moon calc(var(--speed) * 2.8) ease-in-out infinite; }
@keyframes darma-loader-darma-research-cosmic-eclipse-core-eclipse-moon { 0%,100% { transform: translateX(-8%); } 50% { transform: translateX(82%); } }
@keyframes darma-loader-darma-research-cosmic-eclipse-core-eclipse-pulse { 50% { transform: scale(1.06); } }
@keyframes darma-loader-darma-research-cosmic-eclipse-core-eclipse-rays { to { rotate: 360deg; } }

